import {
  Component, effect, signal, untracked, inject, output
} from '@angular/core';

import { Response } from '@iqbspecs/response/response.interface';
import {
  InteractionMetaParams
} from '../../models/unit-definition';
import { InteractionComponentDirective } from '../../directives/interaction-component.directive';

import { StandardButtonComponent } from '../../shared/standard-button/standard-button.component';
import { StarsResponse } from '../../services/responses.service';
import { UnitService } from '../../services/unit.service';

@Component({
  selector: 'stars-interaction-meta',
  templateUrl: './interaction-meta.component.html',
  styleUrls: ['./interaction-meta.component.scss'],
  imports: [
    StandardButtonComponent
  ]
})

export class InteractionMetaComponent extends InteractionComponentDirective {
  navigationNextRequest = output<string>();
  unitService = inject(UnitService);

  /** Local copy of the component parameters with defaults applied. */
  localParameters!: InteractionMetaParams;

  /** Reference to the last processed parameters object to detect object-identity changes. */
  private lastParametersRef: unknown | null = null;

  /** If there is a hint to be shown */
  hasHint = signal(false);

  /** Array of booleans for each option for selected values. */
  selectedValues = signal<boolean[]>([]);
  /** Array of booleans for each option for hint values. */
  hintValues = signal<boolean[]>([]);
  /** Flat list of options. */
  buttons = signal<{ imageSource: string }[]>([
    // eslint-disable-next-line max-len
    { imageSource: 'data:image/png;base64,' },
    // eslint-disable-next-line max-len
    { imageSource: 'data:image/png;base64,' },
    // eslint-disable-next-line max-len
    { imageSource: 'data:image/png;base64,' },
    // eslint-disable-next-line max-len
    { imageSource: 'data:image/png;base64,' }
  ]);

  constructor() {
    super();

    effect(() => {
      const parameters = this.parameters() as InteractionMetaParams;
      if (!parameters) return;

      const isNewParametersObject = this.lastParametersRef !== parameters;

      if (isNewParametersObject) {
        this.lastParametersRef = parameters;

        this.localParameters = {
          ...this.createDefaultParameters(),
          ...parameters
        };
        this.localParameters.variableId = this.localParameters.variableId || 'META';

        // Only restore from former state once, on initial load
        const formerStateResponse: Response[] = this.localParameters.formerState || [];

        if (Array.isArray(formerStateResponse) && formerStateResponse.length > 0) {
          const foundResponse = formerStateResponse.find(
            response => response.id === this.localParameters.variableId
          );

          if (foundResponse && foundResponse.value) {
            this.restoreFromFormerState(foundResponse);
            return;
          }
        }

        this.resetSelection();

        this.responses.emit([{
          id: this.localParameters.variableId,
          status: 'DISPLAYED',
          value: untracked(() => this.getSelectedValue()),
          relevantForResponsesProgress: true
        } as StarsResponse]);
      } else {
        // Same unit, just keep localParameters' formerState in sync if needed
        this.localParameters.formerState = parameters.formerState;
      }
    });

    effect(() => {
      const hints = this.showHint();
      if (!hints || hints.length === 0) {
        this.hintValues.set([]);
        this.hasHint.set(false);
        return;
      }

      // set single select: "2" => [false, true, false]
      const selectedIndex = parseInt(hints, 10) - 1;
      const selectedStates = Array.from(
        { length: this.buttons().length },
        (_, i) => i === selectedIndex
      );
      this.hintValues.set(selectedStates);
      this.selectedValues.set([]);
      this.hasHint.set(true);
    });
  }

  private getSelectedValue() {
    return (this.selectedValues().findIndex(item => item) + 1).toString();
  }

  private resetSelection(): void {
    const numberOfOptions = this.buttons().length;
    this.selectedValues.set(Array.from(
      { length: numberOfOptions },
      () => false
    ));
    this.hintValues.set(Array.from(
      { length: numberOfOptions },
      () => false
    ));
  }

  /**
   * Restores the selection state based on user interaction.
   * @param {Response} response - The response object containing a string `value`.
   */
  private restoreFromFormerState(response: Response): void {
    if (!response.value || typeof response.value !== 'string') {
      return;
    }
    const selectedIndex = parseInt(response.value, 10) - 1;
    const numberOfOptions = this.buttons().length;

    const selectedValues = Array.from(
      { length: numberOfOptions },
      (_, i) => i === selectedIndex
    );
    this.selectedValues.set(selectedValues);
  }

  onButtonClick(index: number): void {
    const numberOfOptions = this.buttons().length;
    const selectedValues = Array.from(
      { length: numberOfOptions },
      (_, i) => i === index
    );
    this.selectedValues.set(selectedValues);
    this.hasHint.set(false);
    this.hintValues.set(Array.from(
      { length: numberOfOptions },
      () => false
    ));

    const value = (this.selectedValues().findIndex(item => item) + 1).toString();

    const response: StarsResponse = {
      id: this.localParameters.variableId || 'META',
      status: 'VALUE_CHANGED',
      value: value,
      relevantForResponsesProgress: true
    };

    this.responses.emit([response]);

    if (this.unitService.closingMetaButtons().triggerNavigationOnSelect) {
      setTimeout(() => {
        this.navigationNextRequest.emit('next');
      }, 500);
    }
  }

  // eslint-disable-next-line class-methods-use-this
  private createDefaultParameters(): InteractionMetaParams {
    return {
      variableId: 'META'
    };
  }
}
